CREATE TABLE IF NOT EXISTS alerts (id uuid PRIMARY KEY, organization_id uuid NOT NULL REFERENCES organizations(id) ON DELETE CASCADE, entity_type text NOT NULL, entity_id text NOT NULL, title text NOT NULL, message text NOT NULL, severity text NOT NULL CHECK (severity IN ('LOW','MEDIUM','HIGH','CRITICAL')), status text NOT NULL DEFAULT 'OPEN' CHECK (status IN ('OPEN','ACKNOWLEDGED','RESOLVED')), detected_at timestamptz NOT NULL DEFAULT now(), metadata jsonb NOT NULL DEFAULT '{}');
CREATE INDEX IF NOT EXISTS alerts_organization_detected_idx ON alerts (organization_id, detected_at DESC);
